                WHERE sc.code = #{vo.code}
            )


            AND p.brand_id = #{vo.brandId}


            AND (p.category_id = #{vo.categoryId} OR FIND_IN_SET(#{vo.categoryId}, rm.path))


            AND p.name LIKE CONCAT('%', #{vo.name}, '%')


            AND p.short_name LIKE CONCAT('%', #{vo.shortName}, '%')


            AND p.product_type = #{vo.productType}


            AND p.create_time >= #{vo.startTime}



            AND p.create_time <= #{vo.endTime}



    AND p.available = TRUE
    AND s.available = TRUE

ORDER BY p.code, s.code


WHERE s.id IN
#{item}
